import { Pipe, PipeTransform } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

@Pipe({
    name: 'svgIcon',
})
export class SvgIconPipe implements PipeTransform {
    constructor(private sanitizer: DomSanitizer) { }

    private svgIcons: { [key: string]: string } = {
        "sidebar-analytics": `<svg width="currentWidth" height="currentHeight" viewBox="0 0 15 15" fill="none"
                                xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
                                <rect width="currentWidth" height="currentHeight" fill="url(#pattern0_2293_1066)" />
                                <defs>
                                    <pattern id="pattern0_2293_1066" patternContentUnits="objectBoundingBox" width="1"
                                        height="1">
                                        <use xlink:href="#image0_2293_1066" transform="scale(0.00195312)" />
                                    </pattern>
                                    <image id="image0_2293_1066" width="512" height="512" preserveAspectRatio="none"
                                        xlink:href="data:image/png;base64," />
                                </defs>
                            </svg>`,
        "sidebar-dashboard": `<svg xmlns="http://www.w3.org/2000/svg" width="currentWidth" height="currentHeight" viewBox="0 0 24 24"
                                fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"
                                stroke-linejoin="round">
                                <path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path>
                                <polyline points="9 22 9 12 15 12 15 22"></polyline>
                            </svg>`,
        'sidebar-collaborators': `<svg xmlns="http://www.w3.org/2000/svg" width="currentWidth" height="currentHeight" viewBox="0 0 24 24"
                                fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"
                                stroke-linejoin="round">
                                <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path>
                                <circle cx="9" cy="7" r="4"></circle>
                                <path d="M23 21v-2a4 4 0 0 0-3-3.87"></path>
                                <path d="M16 3.13a4 4 0 0 1 0 7.75"></path>
                            </svg>`,
        'sidebar-integ': `<svg width="currentWidth" height="currentHeight" viewBox="0 0 15 15" fill="none"
                                xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
                                <rect width="currentWidth" height="currentHeight" fill="url(#pattern0_2305_1499)" />
                                <defs>
                                    <pattern id="pattern0_2305_1499" patternContentUnits="objectBoundingBox" width="1"
                                        height="1">
                                        <use xlink:href="#image0_2305_1499" transform="scale(0.00195312)" />
                                    </pattern>
                                    <image id="image0_2305_1499" width="512" height="512" preserveAspectRatio="none"
                                        xlink:href="data:image/png;base64," />
                                </defs>
                            </svg>`,
        'sidebar-settings': `<svg width="currentWidth" height="currentHeight" viewBox="0 0 15 15" fill="none"
                                xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
                                <rect width="15" height="15" fill="url(#pattern0_2305_1510)" />
                                <defs>
                                    <pattern id="pattern0_2305_1510" patternContentUnits="objectBoundingBox" width="1"
                                        height="1">
                                        <use xlink:href="#image0_2305_1510" transform="scale(0.00195312)" />
                                    </pattern>
                                    <image id="image0_2305_1510" width="512" height="512" preserveAspectRatio="none"
                                        xlink:href="data:image/png;base64," />
                                </defs>
                            </svg>`,
        "sidebar-tools": `<svg xmlns="http://www.w3.org/2000/svg" width="currentWidth" height="currentHeight" viewBox="0 0 24 24"
                                fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"
                                stroke-linejoin="round">
                                <path
                                    d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z">
                                </path>
                            </svg>`,
        "sidebar-support": `<svg xmlns="http://www.w3.org/2000/svg" width="currentWidth" height="currentHeight" viewBox="0 0 24 24"
                                fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"
                                stroke-linejoin="round">
                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
                            </svg>`,
        "sidebar-logout": `<svg xmlns="http://www.w3.org/2000/svg" width="currentWidth" height="currentHeight" viewBox="0 0 24 24" fill="none"
                    stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                    <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"></path>
                    <polyline points="16 17 21 12 16 7"></polyline>
                    <line x1="21" y1="12" x2="9" y2="12"></line>
                </svg>`,
        "admin-chev": `<svg width="currentWidth" height="currentHeight" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <path d="M5 7.5L10 12.5L15 7.5" stroke="#EFEFEF" stroke-width="2" stroke-linecap="round"
                            stroke-linejoin="round" />
                    </svg>`
    };

    transform(
        iconName: string,
        color?: string,
        height?: number,
        width?: number
    ): SafeHtml {
        let svgContent = this.svgIcons[iconName] || '';

        // Se uma cor for fornecida, substitua todas as ocorrências de stroke="currentColor" no SVG
        if (color) {
            const regex = /currentColor/g;
            svgContent = svgContent.replace(regex, `${color}`);
        }

        if (height) {
            const regex = /currentWidth/g;
            svgContent = svgContent.replace(regex, `${height}`);
        }
        if (width) {
            const regex = /currentHeight/g;
            svgContent = svgContent.replace(regex, `${width}`);
        }

        return this.sanitizer.bypassSecurityTrustHtml(svgContent);
    }
}
